def power(l, r, k):
    if k == 1:
        return []
    i = 0
    while k ** i <= r:
        i += 1
    i -= 1
    ans = []
    while k ** i >= l:
        ans.append(k ** i)
        i -= 1
    return ans


l, r, k = map(int, input().split())
ans = power(l, r, k)
if ans:
    print(*ans)
else:
    print(-1)
